string removeAllBalls(string board) {
string res = update(board);
while (res != board) {
board = res;
res = update(board);
}
return res;
}

string update(string s) {
string res = "";
int l = 0, r = 0;
while (r < s.size()) {
r++;
if (s[r] != s[l]) {
if (r - l < 3) {
for (int i=l; i<r; i++) {
res += s[i];
}
}
l = r;
}
}
if (l - r < 3) {
for (int i=l; i<r; i++) {
res += s[i];
}
}
return res;
}
};
